def duplicate_count(lst):
    """
    Count the number of duplicates in a list.

    Args:
        lst (list): A list of elements.

    Returns:
        dict: A dictionary where keys are the elements that appear at least twice and values are their counts.
    """
    count_dict = {}
    for elem in lst:
        if elem in count_dict:
            count_dict[elem] += 1
        else:
            count_dict[elem] = 1
    return {k: v for k, v in count_dict.items() if v > 1}
