class SegmentTree:
    def __init__(self, nums):
        self.tree = [None] * len(nums)
        for i in range(len(nums)):
            self.tree[i] = [nums[i], nums[i]]
        self.build_tree()

    def build_tree(self):
        for i in range(len(self.tree) // 2, 0, -1):
            self._merge(i)

    def _merge(self, idx):
        child_left = self.tree[idx * 2]
        child_right = self.tree[idx * 2 + 1]
        if max(child_left) > max(child_right):
            self.tree[idx] = child_left
        else:
            self.tree[idx] = child_right

    def query(self, left, right):
        return max(self.tree[self._query_range(left, right)])

    def _query_range(self, left, right):
        range_idx = left + (right - left) // 2
        while range_idx >= 1:
            if left <= range_idx * 2 and right >= range_idx * 2 + 1:
                if max(self.tree[range_idx * 2]) > max(self.tree[range_idx * 2 + 1]):
                    return range_idx * 2
                else:
                    return range_idx * 2 + 1
            elif left <= range_idx * 2:
                return range_idx * 2
            elif right >= range_idx * 2 + 1:
                return range_idx * 2 + 1
            else:
                range_idx //= 2

